mapper.select:
/* IResidentFacilityMapper.selectResidentFacilityInfoList */ SELECT * FROM ( SELECT rownum rn , a.* FROM ( SELECT f.facility_no facilityNo , f.facility_ty_cd facilityTyCd , ft.code_name facilityTyNm , f.facility_nm facilityNm , f.dong_no dongNo , f.loc_cn locCn , f.use_yn useYn FROM facility f LEFT JOIN common_code ft ON ft.group_code_no = 'FACILITY_TY' AND ft.code_no_cd = f.facility_ty_cd AND ft.use_yn = 'Y' WHERE f.apt_cmplex_no = #{aptCmplexNo} AND NVL(f.use_yn, 'Y') = 'Y'
AND ( f.facility_ty_cd LIKE '%' || #{facilityTyCd} || '%' OR ft.code_name LIKE '%' || #{facilityTyCd} || '%' OR CASE f.facility_ty_cd WHEN 'COMM' THEN '커뮤니티시설' WHEN 'ELV' THEN '엘리베이터' WHEN 'GYM' THEN '피트니스센터' WHEN 'SEC' THEN '보안시설' WHEN 'PLAY' THEN '어린이 놀이시설' WHEN 'STUDY' THEN '독서실' WHEN 'PARK' THEN '입주민 주차장' WHEN 'PARKING' THEN '방문자 주차구역' WHEN 'MEET' THEN '주민회의실' WHEN 'WTR' THEN '수도시설' WHEN 'ELC' THEN '전기시설' WHEN 'GAS' THEN '가스시설' WHEN 'FIRE' THEN '소방시설' ELSE '기타시설' END LIKE '%' || #{facilityTyCd} || '%' )
AND f.facility_nm LIKE '%' || #{facilityNm} || '%'
AND f.dong_no = #{dongNo}
AND f.loc_cn LIKE '%' || #{locCn} || '%'
ORDER BY ${sortColumn} ${sortOrder} ) a WHERE rownum <= #{endRow} ) WHERE rn >= #{startRow}

/* IResidentFacilityMapper.selectResidentFacilityInfoCount */ SELECT COUNT(*) FROM facility f LEFT JOIN common_code ft ON ft.group_code_no = 'FACILITY_TY' AND ft.code_no_cd = f.facility_ty_cd AND ft.use_yn = 'Y' WHERE f.apt_cmplex_no = #{aptCmplexNo} AND NVL(f.use_yn, 'Y') = 'Y'
AND ( f.facility_ty_cd LIKE '%' || #{facilityTyCd} || '%' OR ft.code_name LIKE '%' || #{facilityTyCd} || '%' OR CASE f.facility_ty_cd WHEN 'COMM' THEN '커뮤니티시설' WHEN 'ELV' THEN '엘리베이터' WHEN 'GYM' THEN '피트니스센터' WHEN 'SEC' THEN '보안시설' WHEN 'PLAY' THEN '어린이 놀이시설' WHEN 'STUDY' THEN '독서실' WHEN 'PARK' THEN '입주민 주차장' WHEN 'PARKING' THEN '방문자 주차구역' WHEN 'MEET' THEN '주민회의실' WHEN 'WTR' THEN '수도시설' WHEN 'ELC' THEN '전기시설' WHEN 'GAS' THEN '가스시설' WHEN 'FIRE' THEN '소방시설' ELSE '기타시설' END LIKE '%' || #{facilityTyCd} || '%' )
AND f.facility_nm LIKE '%' || #{facilityNm} || '%'
AND f.dong_no = #{dongNo}
AND f.loc_cn LIKE '%' || #{locCn} || '%'
